import json
import pymysql
import os
import logging

logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Database connection configuration from environment variables
DB_HOST = os.environ.get('DB_HOST', 'localhost')
DB_USER = os.environ.get('DB_USER', 'admin')
DB_PASSWORD = os.environ.get('DB_PASSWORD', 'password')
DB_NAME = os.environ.get('DB_NAME', 'products_db')
DB_PORT = int(os.environ.get('DB_PORT', 3306))


def get_db_connection():
    """Create and return a database connection."""
    try:
        connection = pymysql.connect(
            host=DB_HOST,
            user=DB_USER,
            password=DB_PASSWORD,
            database=DB_NAME,
            port=DB_PORT,
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor,
            connect_timeout=5,
            read_timeout=10,
            write_timeout=10
        )
        return connection
    except pymysql.MySQLError as e:
        logger.error(f"Database connection error: {e}")
        raise


def build_search_query(params):
    """
    Dynamically build SQL query based on search parameters.
    
    Supported parameters:
    - keyword: Search in product name and description
    - category: Filter by category
    - min_price: Minimum price filter
    - max_price: Maximum price filter
    - brand: Filter by brand
    - in_stock: Filter by stock availability (true/false)
    - rating_min: Minimum rating filter
    - sort_by: Sort field (name, price, rating, created_at)
    - sort_order: Sort direction (asc, desc)
    - page: Page number for pagination
    - page_size: Number of results per page
    - tags: Comma-separated list of tags
    - sku: Exact SKU match
    - product_id: Exact product ID match
    """
    base_query = "SELECT * FROM products"
    count_query = "SELECT COUNT(*) as total FROM products"
    conditions = []
    values = []

    # Keyword search across name and description
    if params.get('keyword'):
        keyword = f"%{params['keyword']}%"
        conditions.append("(name LIKE %s OR description LIKE %s)")
        values.extend([keyword, keyword])

    # Category filter
    if params.get('category'):
        conditions.append("category = %s")
        values.append(params['category'])

    # Price range filters
    if params.get('min_price'):
        try:
            min_price = float(params['min_price'])
            conditions.append("price >= %s")
            values.append(min_price)
        except (ValueError, TypeError):
            logger.warning(f"Invalid min_price value: {params['min_price']}")

    if params.get('max_price'):
        try:
            max_price = float(params['max_price'])
            conditions.append("price <= %s")
            values.append(max_price)
        except (ValueError, TypeError):
            logger.warning(f"Invalid max_price value: {params['max_price']}")

    # Brand filter
    if params.get('brand'):
        conditions.append("brand = %s")
        values.append(params['brand'])

    # Stock availability filter
    if params.get('in_stock') is not None:
        in_stock = str(params['in_stock']).lower()
        if in_stock in ('true', '1', 'yes'):
            conditions.append("stock_quantity > 0")
        elif in_stock in ('false', '0', 'no'):
            conditions.append("stock_quantity = 0")

    # Minimum rating filter
    if params.get('rating_min'):
        try:
            rating_min = float(params['rating_min'])
            conditions.append("rating >= %s")
            values.append(rating_min)
        except (ValueError, TypeError):
            logger.warning(f"Invalid rating_min value: {params['rating_min']}")

    # Tags filter (comma-separated, searches in a tags column)
    if params.get('tags'):
        tags = [tag.strip() for tag in params['tags'].split(',') if tag.strip()]
        if tags:
            tag_conditions = []
            for tag in tags:
                tag_conditions.append("FIND_IN_SET(%s, tags) > 0")
                values.append(tag)
            conditions.append(f"({' OR '.join(tag_conditions)})")

    # SKU exact match
    if params.get('sku'):
        conditions.append("sku = %s")
        values.append(params['sku'])

    # Product ID exact match
    if params.get('product_id'):
        try:
            product_id = int(params['product_id'])
            conditions.append("id = %s")
            values.append(product_id)
        except (ValueError, TypeError):
            logger.warning(f"Invalid product_id value: {params['product_id']}")

    # Active/enabled products only (default behavior)
    if params.get('include_inactive') is None or str(params.get('include_inactive')).lower() not in ('true', '1', 'yes'):
        conditions.append("is_active = 1")

    # Build WHERE clause
    where_clause = ""
    if conditions:
        where_clause = " WHERE " + " AND ".join(conditions)

    # Build count query with same conditions
    count_query += where_clause
    count_values = list(values)

    # Sorting - whitelist allowed sort fields to prevent SQL injection
    allowed_sort_fields = {
        'name': 'name',
        'price': 'price',
        'rating': 'rating',
        'created_at': 'created_at',
        'updated_at': 'updated_at',
        'stock_quantity': 'stock_quantity',
        'brand': 'brand',
        'category': 'category'
    }

    sort_by = params.get('sort_by', 'created_at')
    sort_order = params.get('sort_order', 'desc').lower()

    if sort_by not in allowed_sort_fields:
        sort_by = 'created_at'
    else:
        sort_by = allowed_sort_fields[sort_by]

    if sort_order not in ('asc', 'desc'):
        sort_order = 'desc'

    order_clause = f" ORDER BY {sort_by} {sort_order}"

    # Pagination
    try:
        page = max(1, int(params.get('page', 1)))
    except (ValueError, TypeError):
        page = 1

    try:
        page_size = min(100, max(1, int(params.get('page_size', 20))))
    except (ValueError, TypeError):
        page_size = 20

    offset = (page - 1) * page_size
    limit_clause = f" LIMIT %s OFFSET %s"

    # Final query assembly
    final_query = base_query + where_clause + order_clause + limit_clause
    final_values = values + [page_size, offset]

    return {
        'query': final_query,
        'values': final_values,
        'count_query': count_query,
        'count_values': count_values,
        'page': page,
        'page_size': page_size
    }


def build_response(status_code, body, headers=None):
    """Build a standardized API Gateway response."""
    response = {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Content-Type,Authorization',
            'Access-Control-Allow-Methods': 'GET,POST,OPTIONS'
        },
        'body': json.dumps(body, default=str)
    }
    if headers:
        response['headers'].update(headers)
    return response


def extract_search_params(event):
    """
    Extract search parameters from API Gateway event.
    Supports both GET (query string) and POST (body) methods.
    """
    params = {}

    # Extract from query string parameters
    if event.get('queryStringParameters'):
        params.update(event['queryStringParameters'])

    # Extract from multi-value query string parameters
    if event.get('multiValueQueryStringParameters'):
        for key, value_list in event['multiValueQueryStringParameters'].items():
            if len(value_list) > 1:
                params[key] = ','.join(value_list)
            elif len(value_list) == 1:
                if key not in params:
                    params[key] = value_list[0]

    # Extract from request body (for POST requests)
    http_method = event.get('httpMethod', event.get('requestContext', {}).get('http', {}).get('method', 'GET'))

    if http_method == 'POST' and event.get('body'):
        try:
            body = event['body']
            if event.get('isBase64Encoded'):
                import base64
                body = base64.b64decode(body).decode('utf-8')
            body_params = json.loads(body)
            if isinstance(body_params, dict):
                params.update(body_params)
        except (json.JSONDecodeError, TypeError) as e:
            logger.warning(f"Failed to parse request body: {e}")

    # Extract from path parameters
    if event.get('pathParameters'):
        params.update(event['pathParameters'])

    return params


def lambda_handler(event, context):
    """
    Main Lambda handler for product search.
    
    Accepts search parameters via:
    - GET query string parameters
    - POST request body (JSON)
    - Path parameters
    
    Returns paginated search results with metadata.
    """
    logger.info(f"Received event: {json.dumps(event, default=str)}")

    # Handle CORS preflight
    http_method = event.get('httpMethod', event.get('requestContext', {}).get('http', {}).get('method', ''))
    if http_method == 'OPTIONS':
        return build_response(200, {'message': 'CORS preflight response'})

    connection = None

    try:
        # Extract search parameters from the event
        params = extract_search_params(event)
        logger.info(f"Search parameters: {params}")

        if not params:
            return build_response(400, {
                'error': 'Bad Request',
                'message': 'No search parameters provided. Supported parameters: keyword, category, min_price, max_price, brand, in_stock, rating_min, sort_by, sort_order, page, page_size, tags, sku, product_id'
            })

        # Build the dynamic SQL query
        query_data = build_search_query(params)
        logger.info(f"Generated query: {query_data['query']}")

        # Execute the query
        connection = get_db_connection()

        with connection.cursor() as cursor:
            # Get total count for pagination metadata
            cursor.execute(query_data['count_query'], query_data['count_values'])
            count_result = cursor.fetchone()
            total_count = count_result['total'] if count_result else 0

            # Get search results
            cursor.execute(query_data['query'], query_data['values'])
            products = cursor.fetchall()

        # Calculate pagination metadata
        page = query_data['page']
        page_size = query_data['page_size']
        total_pages = (total_count + page_size - 1) // page_size if total_count > 0 else 0

        # Build response
        response_body = {
            'success': True,
            'data': {
                'products': products,
                'pagination': {
                    'current_page': page,
                    'page_size': page_size,
                    'total_results': total_count,
                    'total_pages': total_pages,
                    'has_next_page': page < total_pages,
                    'has_previous_page': page > 1
                }
            },
            'search_params': {k: v for k, v in params.items() if k not in ('password', 'token', 'secret')}
        }

        logger.info(f"Returning {len(products)} products out of {total_count} total matches")
        return build_response(200, response_body)

    except pymysql.MySQLError as e:
        logger.error(f"Database error: {e}")
        return build_response(500, {
            'success': False,
            'error': 'Database Error',
            'message': 'An error occurred while searching products. Please try again later.'
        })

    except json.JSONDecodeError as e:
        logger.error(f"JSON decode error: {e}")
        return build_response(400, {
            'success': False,
            'error': 'Bad Request',
            'message': 'Invalid JSON in request body.'
        })

    except Exception as e:
        logger.error(f"Unexpected error: {e}", exc_info=True)
        return build_response(500, {
            'success': False,
            'error': 'Internal Server Error',
            'message': 'An unexpected error occurred. Please try again later.'
        })

    finally:
        if connection:
            try:
                connection.close()
                logger.info("Database connection closed")
            except Exception as e:
                logger.error(f"Error closing database connection: {e}")